namespace sv_0b10a424dc6e4b30834603d2b2f79ed7.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@using sv_0b10a424dc6e4b30834603d2b2f79ed7.Services

<div class="card h-100 product-card" @onclick="HandleCardClick" role="button">
    <div class="card-img-top bg-secondary d-flex align-items-center justify-content-center"
         style="height: 180px;"
         title="@Product.Name">
        <span class="text-white text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="text-primary fw-bold mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1">@GetStarRating(Product.Rating)</p>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-primary mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private static string GetStarRating(double rating)
    {
        int fullStars = (int)Math.Round(rating);
        int emptyStars = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', emptyStars);
    }
}

@page "/catalog"
@using sv_0b10a424dc6e4b30834603d2b2f79ed7.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* ───── Left Sidebar: Filters ───── *@
    <div class="col-md-3">
        <div class="card">
            <div class="card-header fw-bold">Filters</div>
            <div class="card-body">
                @* Category checkboxes *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label mb-0 small">Min Price</label>
                    <input type="number" class="form-control form-control-sm" @bind="minPrice" min="0" step="0.01" />
                </div>
                <div class="mb-2">
                    <label class="form-label mb-0 small">Max Price</label>
                    <input type="number" class="form-control form-control-sm" @bind="maxPrice" min="0" step="0.01" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ───── Main Content Area ───── *@
    <div class="col-md-9">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (searchResult is not null)
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label mb-0 me-2 small">Sort by:</label>
                    <select class="form-select form-select-sm d-inline-block w-auto" @onchange="OnSortChanged">
                        @foreach (var opt in sortOptions)
                        {
                            <option value="@opt.Value" selected="@(sortBy == opt.Value)">@opt.Label</option>
                        }
                    </select>
                </div>
                <span class="text-muted small">
                    @GetShowingLabel()
                </span>
            </div>

            @if (searchResult.Items.Count == 0)
            {
                <div class="alert alert-info" role="alert">
                    No products match your filters. Try adjusting your criteria.
                </div>
            }
            else
            {
                @* Product Grid *@
                <div class="row row-cols-1 row-cols-sm-2 row-cols-lg-3 g-3 mb-3">
                    @foreach (var product in searchResult.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductSelected="HandleProductSelected"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (totalPages > 1)
                {
                    <nav aria-label="Product pagination">
                        <ul class="pagination justify-content-center">
                            <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage - 1)" disabled="@(currentPage == 1)">Previous</button>
                            </li>
                            @for (int i = 1; i <= totalPages; i++)
                            {
                                var pageNum = i;
                                <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                                </li>
                            }
                            <li class="page-item @(currentPage == totalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPage(currentPage + 1)" disabled="@(currentPage == totalPages)">Next</button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        }
    </div>
</div>

@code {
    // ── Filter state ──
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    // ── Sort / paging ──
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 9;

    // ── Results ──
    private PagedResult<Product>? searchResult;
    private bool isLoading = true;
    private string? errorMessage;

    private int totalPages => searchResult is null || searchResult.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)searchResult.TotalCount / PageSize);

    private static readonly (string Value, string Label)[] sortOptions =
    {
        ("price_asc", "Price: Low to High"),
        ("price_desc", "Price: High to Low"),
        ("name_asc", "Name: A-Z"),
        ("rating_desc", "Rating: Highest")
    };

    // ── Lifecycle ──

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ExecuteSearchAsync();

            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task ExecuteSearchAsync()
    {
        try
        {
            isLoading = true;
            errorMessage = null;

            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            searchResult = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    // ── Filter handlers ──

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await ExecuteSearchAsync();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        currentPage = 1;
        await ExecuteSearchAsync();
    }

    // ── Sort handler ──

    private async Task OnSortChanged(ChangeEventArgs e)
    {
        sortBy = e.Value?.ToString() ?? "price_asc";
        currentPage = 1;
        await ExecuteSearchAsync();
    }

    // ── Pagination ──

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > totalPages) return;
        currentPage = page;
        await ExecuteSearchAsync();
    }

    // ── Product interactions ──

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder – wire up cart service here
        return Task.CompletedTask;
    }

    // ── Helpers ──

    private string GetShowingLabel()
    {
        if (searchResult is null || searchResult.TotalCount == 0)
            return "No products";

        int start = (searchResult.Page - 1) * searchResult.PageSize + 1;
        int end = Math.Min(start + searchResult.Items.Count - 1, searchResult.TotalCount);
        return $"Showing {start}\u2013{end} of {searchResult.TotalCount} products";
    }
}

